import React from 'react';
import './Feature.css';
import TentImg from "../Assets/tent.jpg"; // Replace with actual image paths
import BBQImg from '../Assets/bbq.jpg';
// import SnacksImg from '../Assets/snacks.jpg';
// import LunchImg from '../Assets/lunch.jpg';
// import BreakfastImg from '../Assets/breakfast.jpg';
// import CottageImg from '../Assets/cottage.jpg';
// import DomeImg from '../Assets/dome.jpg';
// import GamingImg from '../Assets/gaming.jpg';

const Feature = () => {
  const packages = [
    {
      name: "Tent Package",
      features: [
        { name: "Tent Stay", img: TentImg },
        { name: "BBQ Night", img: BBQImg },
        { name: "Snacks", img: SnacksImg },
        { name: "Unlimited Lunch", img: LunchImg },
        { name: "Morning Breakfast", img: BreakfastImg },
      ],
    },
    {
      name: "Cottage Package",
      features: [
        { name: "Cottage Stay", img: CottageImg },
        { name: "BBQ Night", img: BBQImg },
        { name: "Snacks", img: SnacksImg },
        { name: "Unlimited Lunch", img: LunchImg },
        { name: "Morning Breakfast", img: BreakfastImg },
      ],
    },
    {
      name: "Dome Package",
      features: [
        { name: "Dome Stay", img: DomeImg },
        { name: "BBQ Night", img: BBQImg },
        { name: "Snacks", img: SnacksImg },
        { name: "Unlimited Lunch", img: LunchImg },
        { name: "Gaming Activities", img: GamingImg },
      ],
    },
  ];

  return (
    <div className="packages-container">
      <h2 className="heading">Our Feature Packages</h2>
      {packages.map((pack, index) => (
        <div className="package" key={index}>
          <h3 className="package-name">{pack.name}</h3>
          <div className="features">
            {pack.features.map((feature, i) => (
              <div className="feature-item" key={i}>
                <img src={feature.img} alt={feature.name} className="feature-image" />
                <p className="feature-name">{feature.name}</p>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

export default Feature;
